function featureCardClassName(size: FeatureCard["size"]) {
  if (size === "large") {
    return `${styles.featureCard} ${styles.featureCardLarge}`;
  }

  if (size === "wide") {
    return `${styles.featureCard} ${styles.featureCardWide}`;
  }

  return `${styles.featureCard} ${styles.featureCardSmall}`;
}

function DeployButton({
  href,
  label,
  iconSrc,
  className,
}: {
  href: string;
  label: string;
  iconSrc: string;
  className?: string;
}) {
  return (
    <ProtectedRouteLink
      className={`${styles.buttonDark} ${className ?? ""}`.trim()}
      href={href}
    >
      <span>{label}</span>
      <Image src={iconSrc} alt="" width={16} height={16} aria-hidden="true" />
    </ProtectedRouteLink>
  );
}

